  // Emits types with TypeScript
}
```

**helpers/compile/configs.ts:**

```typescript
export function createAdapterConfig(entries: AdapterEntry[]): BuildOptions[] {
  return entries.flatMap(({ entry, outfile }) => {
    const baseName = path.basename(outfile)

    return [
      {
        name: `${baseName}-cjs`,
        format: 'cjs',
        bundle: true,
        entryPoints: [entry],
        outfile,
        outExtension: { '.js': '.js' },
        emitTypes: true,
      },
      {
        name: `${baseName}-esm`,
        format: 'esm',
        bundle: true,
        entryPoints: [entry],
        outfile,
        outExtension: { '.js': '.mjs' },
        emitTypes: true,
      },
    ]
  })
}

export const adapterConfig = createAdapterConfig([
  { entry: 'src/index.ts', outfile: 'dist/index' }
])
```

---

### 9. **KEY PATTERNS TO REPLICATE**

1. **Dual Build Outputs**: All generator packages output both CJS (`.js`) and ESM (`.mjs`) with matching type definitions (`.d.ts` and `.d.mts`)

2. **Generator Handler Pattern**:
   - Create a class implementing `Generator` interface
   - Use `generatorHandler()` wrapper for JSON-RPC communication
   - `onManifest()` is optional, returns metadata about the generator
   - `onGenerate()` receives `GeneratorOptions` with full DMMF, datasources, schema, etc.

3. **Configuration Convention**: Config values in `schema.prisma` are accessed via `options.generator.config` and are always strings or string arrays

4. **Build Setup**: All generators use identical tsconfig inheritance and the shared `helpers/compile/build` system with esbuild

5. **Dependencies**: Generator packages depend on:
   - `@prisma/generator` (types)
   - `@prisma/generator-helper` (handler)
   - `@prisma/dmmf` (type definitions)
   - `@prisma/debug` (logging)
   - Other internal packages as needed

