import type { Field } from '@prisma/generator'

const SCALAR_TYPE_MAP: Record<string, string> = {
  String: 'string',
  Boolean: 'boolean',
  Int: 'number',
  Float: 'number',
  Decimal: 'string',
  BigInt: 'bigint',
  DateTime: 'Date | string',
  Json: 'unknown',
  Bytes: 'Buffer',
}

/**
 * Maps a Prisma scalar type name to the corresponding TypeScript type.
 * Returns `string` for unrecognized types (e.g. custom enums are handled
 * separately by the generator).
 */
export function mapScalarType(prismaType: string): string {
  return SCALAR_TYPE_MAP[prismaType] ?? 'string'
}

/**
 * Wraps a TypeScript type string based on whether the field is a list or
 * optional (not required).
 */
export function wrapFieldType(tsType: string, field: Readonly<Pick<Field, 'isList' | 'isRequired'>>): string {
  if (field.isList) {
    return `${tsType}[]`
  }
  if (!field.isRequired) {
    return `${tsType} | null`
  }
  return tsType
}

/** Produces a single-line JSDoc comment, or empty string if text is empty. */
export function docComment(text: string | undefined, indent: string): string {
  if (!text) return ''
  return `${indent}/** ${text} */\n`
}

/** Standard file header for every generated file. */
export function fileHeader(): string {
  return [
    '// -----------------------------------------------------------------------',
    '// This file was generated by @prisma/generator-rest-client.',
    '// Do not edit it manually.',
    '// -----------------------------------------------------------------------',
    '',
  ].join('\n')
}

/** Renders an enum declaration from a name and list of values. */
export function renderEnum(name: string, values: readonly string[]): string {
  const members = values.map((v) => `  ${v} = '${v}',`).join('\n')
  return `export enum ${name} {\n${members}\n}\n`
}

