import fs from 'node:fs'
import path from 'node:path'

import type { GeneratorOptions } from '@prisma/generator'
import type * as DMMF from '@prisma/dmmf'

import { docComment, fileHeader, mapScalarType, renderEnum, wrapFieldType } from './template'

/**
 * Core generation logic: reads the DMMF from generator options and writes a
 * fully-typed REST API client file into the configured output directory.
 */
export async function generate(options: GeneratorOptions): Promise<void> {
  const outputDir = options.generator.output?.value
  if (!outputDir) {
    throw new Error('@prisma/generator-rest-client: No output directory specified.')
  }

  const { models, enums } = options.dmmf.datamodel

  const sections: string[] = [fileHeader()]

  // -- Enums -----------------------------------------------------------------
  for (const enumDef of enums) {
    const values = enumDef.values.map((v) => v.name)
    sections.push(renderEnum(enumDef.name, values))
  }

  // -- Model interfaces & client class per model -----------------------------
  const clientMethods: string[] = []

  for (const model of models) {
    sections.push(renderModelInterface(model))
    sections.push(renderCreateInput(model))
    sections.push(renderUpdateInput(model))
    sections.push(renderWhereUniqueInput(model))
    clientMethods.push(renderModelClient(model))
  }

  // -- Top-level REST client -------------------------------------------------
  sections.push(renderRestClient(models, clientMethods))

  const output = sections.join('\n')

  await fs.promises.mkdir(outputDir, { recursive: true })
  await fs.promises.writeFile(path.join(outputDir, 'rest-client.ts'), output, 'utf-8')
}

// ---------------------------------------------------------------------------
// Interface rendering
// ---------------------------------------------------------------------------

function renderModelInterface(model: DMMF.Model): string {
  const lines: string[] = []
  lines.push(docComment(model.documentation, ''))
  lines.push(`export interface ${model.name} {`)

  for (const field of model.fields) {
    if (field.kind === 'object') continue

    const tsType = resolveFieldType(field)
    lines.push(docComment(field.documentation, '  '))
    lines.push(`  ${field.name}: ${tsType}`)
  }

  lines.push('}\n')
  return lines.join('\n')
}

function renderCreateInput(model: DMMF.Model): string {
  const lines: string[] = []
  lines.push(`export interface ${model.name}CreateInput {`)

  for (const field of model.fields) {
    if (field.kind === 'object') continue
    // Fields with defaults, auto-generated ids, and updatedAt are optional on create
    if (field.isReadOnly) continue

    const tsType = resolveFieldType(field)
    const optional = field.hasDefaultValue || field.isGenerated || field.isUpdatedAt || !field.isRequired
    lines.push(`  ${field.name}${optional ? '?' : ''}: ${tsType}`)
  }

  lines.push('}\n')
  return lines.join('\n')
}

function renderUpdateInput(model: DMMF.Model): string {
  const lines: string[] = []
  lines.push(`export interface ${model.name}UpdateInput {`)

  for (const field of model.fields) {
    if (field.kind === 'object') continue
    if (field.isReadOnly) continue
    if (field.isId) continue

    const tsType = resolveFieldType(field)
    lines.push(`  ${field.name}?: ${tsType}`)
  }

  lines.push('}\n')
  return lines.join('\n')
}

function renderWhereUniqueInput(model: DMMF.Model): string {
  const lines: string[] = []
  lines.push(`export interface ${model.name}WhereUniqueInput {`)

  for (const field of model.fields) {
    if (field.kind === 'object') continue

    // Include id and unique fields as optional keys so callers can identify by any unique field
    if (field.isId || field.isUnique) {
      const tsType = resolveFieldType(field)
      lines.push(`  ${field.name}?: ${tsType}`)
    }
  }

  lines.push('}\n')
  return lines.join('\n')
}

// ---------------------------------------------------------------------------
// Per-model REST client methods
// ---------------------------------------------------------------------------

function renderModelClient(model: DMMF.Model): string {
  const name = model.name
  const nameLower = name.charAt(0).toLowerCase() + name.slice(1)
  const nameParam = `${nameLower}s`

  return `  readonly ${nameLower} = {
    /**
     * Find multiple ${name} records.
     */
    findMany: async (args?: { query?: Record<string, string> }): Promise<${name}[]> => {
      const query = args?.query ? '?' + new URLSearchParams(args.query).toString() : ''
      const response = await this.#fetch(\`/\${this.#basePath}/${nameParam}\${query}\`)
      return response.json() as Promise<${name}[]>
    },

    /**
     * Find a unique ${name} record.
     */
    findUnique: async (where: ${name}WhereUniqueInput): Promise<${name} | null> => {
      const id = ${renderIdExtraction(model)}
      const response = await this.#fetch(\`/\${this.#basePath}/${nameParam}/\${encodeURIComponent(String(id))}\`)
      if (response.status === 404) return null
      return response.json() as Promise<${name}>
    },

