    /**
     * Create a new ${name} record.
     */
    create: async (data: ${name}CreateInput): Promise<${name}> => {
      const response = await this.#fetch(\`/\${this.#basePath}/${nameParam}\`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(data),
      })
      return response.json() as Promise<${name}>
    },

    /**
     * Update an existing ${name} record.
     */
    update: async (where: ${name}WhereUniqueInput, data: ${name}UpdateInput): Promise<${name}> => {
      const id = ${renderIdExtraction(model)}
      const response = await this.#fetch(\`/\${this.#basePath}/${nameParam}/\${encodeURIComponent(String(id))}\`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(data),
      })
      return response.json() as Promise<${name}>
    },

    /**
     * Delete a ${name} record.
     */
    delete: async (where: ${name}WhereUniqueInput): Promise<${name}> => {
      const id = ${renderIdExtraction(model)}
      const response = await this.#fetch(\`/\${this.#basePath}/${nameParam}/\${encodeURIComponent(String(id))}\`, {
        method: 'DELETE',
      })
      return response.json() as Promise<${name}>
    },
  }
`
}

/**
 * Produces an expression that extracts the first id/unique value from a
 * WhereUniqueInput object. Falls back to the first field in the model if
 * none are explicitly marked.
 */
function renderIdExtraction(model: DMMF.Model): string {
  const idField = model.fields.find((f) => f.isId) ?? model.fields.find((f) => f.isUnique)

  if (idField) {
    return `where.${idField.name}`
  }

  // Composite-key fallback: use the first scalar field
  const firstScalar = model.fields.find((f) => f.kind === 'scalar')
  return firstScalar ? `where.${firstScalar.name}` : `Object.values(where)[0]`
}

// ---------------------------------------------------------------------------
// Top-level client class
// ---------------------------------------------------------------------------

function renderRestClient(models: readonly DMMF.Model[], methods: string[]): string {
  return `export interface RestClientOptions {
  /** Base URL of the REST API (e.g. "https://api.example.com"). */
  baseUrl: string
  /**
   * Optional base path prepended to every route (e.g. "api/v1").
   * Defaults to an empty string.
   */
  basePath?: string
  /** Optional headers sent with every request. */
  headers?: Record<string, string>
  /**
   * Optional custom fetch implementation.
   * Defaults to the global \`fetch\`.
   */
  fetch?: typeof fetch
}

export class RestClient {
  readonly #baseUrl: string
  readonly #basePath: string
  readonly #headers: Record<string, string>
  readonly #customFetch: typeof fetch

  constructor(options: RestClientOptions) {
    this.#baseUrl = options.baseUrl.replace(/\\/+$/, '')
    this.#basePath = (options.basePath ?? '').replace(/^\\/+|\/+$/g, '')
    this.#headers = options.headers ?? {}
    this.#customFetch = options.fetch ?? globalThis.fetch
  }

  async #fetch(path: string, init?: RequestInit): Promise<Response> {
    const url = \`\${this.#baseUrl}\${path}\`
    const response = await this.#customFetch(url, {
      ...init,
      headers: {
        ...this.#headers,
        ...init?.headers,
      },
    })
    if (!response.ok && response.status !== 404) {
      throw new Error(\`REST client request failed: \${response.status} \${response.statusText}\`)
    }
    return response
  }

${methods.join('\n')}
}
`
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function resolveFieldType(field: DMMF.Field): string {
  if (field.kind === 'enum') {
    return wrapFieldType(field.type, field)
  }

  const tsType = mapScalarType(field.type)
  return wrapFieldType(tsType, field)
}

import type { Field } from '@prisma/dmmf'

const SCALAR_TYPE_MAP: Record<string, string> = {
  String: 'string',
  Boolean: 'boolean',
  Int: 'number',
  Float: 'number',
  Decimal: 'string',
  BigInt: 'bigint',
  DateTime: 'Date | string',
  Json: 'unknown',
  Bytes: 'Buffer',
}

/**
 * Maps a Prisma scalar type name to the corresponding TypeScript type.
 * Returns `string` for unrecognized types (e.g. custom enums are handled
 * separately by the generator).
 */
export function mapScalarType(prismaType: string): string {
  return SCALAR_TYPE_MAP[prismaType] ?? 'string'
}

/**
 * Wraps a TypeScript type string based on whether the field is a list or
 * optional (not required).
 */
export function wrapFieldType(tsType: string, field: Readonly<Pick<Field, 'isList' | 'isRequired'>>): string {
  if (field.isList) {
    return `${tsType}[]`
  }
  if (!field.isRequired) {
    return `${tsType} | null`
  }
  return tsType
}

/** Produces a single-line JSDoc comment, or empty string if text is empty. */
export function docComment(text: string | undefined, indent: string): string {
  if (!text) return ''
  return `${indent}/** ${text} */\n`
}

/** Standard file header for every generated file. */
export function fileHeader(): string {
  return [
    '// -----------------------------------------------------------------------',
    '// This file was generated by @prisma/generator-rest-client.',
    '// Do not edit it manually.',
    '// -----------------------------------------------------------------------',
    '',
  ].join('\n')
}

/** Renders an enum declaration from a name and list of values. */
export function renderEnum(name: string, values: readonly string[]): string {
  const members = values.map((v) => `  ${v} = '${v}',`).join('\n')
  return `export enum ${name} {\n${members}\n}\n`
}

